"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[66879],{54199:(e,i,n)=>{n.r(i),n.d(i,{data:()=>s});const s={key:"v-2b28c7db",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/12.%E5%9B%9E%E4%BC%A0%E4%BA%8B%E4%BB%B6IPostBackEventHandler.html",title:"自定义控件(十二)-回传事件IPostBackEventHandler",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/12.回传事件IPostBackEventHandler.md"}},60352:(e,i,n)=>{n.r(i),n.d(i,{default:()=>t});const s=(0,n(57293).uE)('<h1 id="自定义控件-十二-回传事件ipostbackeventhandler" tabindex="-1"><a class="header-anchor" href="#自定义控件-十二-回传事件ipostbackeventhandler" aria-hidden="true">#</a> 自定义控件(十二)-回传事件IPostBackEventHandler</h1><p>如果一个服务器控件需要支持回传事件，那么它必须要实现IPostBackEventHandler接口</p><p>需要实现RaisePostBackEvent(string eventArgument)方法</p><p>控件代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System;\nusing System.ComponentModel;\nusing System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.IPostBack\n{\n    [ParseChildren(true),            //解析为属性\n    DefaultEvent(&quot;Click&quot;)] \n    public class IPostBackTest2 : WebControl, IPostBackEventHandler\n    {\n        //外层DIV\n        protected override HtmlTextWriterTag TagKey\n        {\n            get { return HtmlTextWriterTag.Div; }\n        }\n        /// &lt;summary&gt;\n        /// 给Div添加属性和样式\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;writer&quot;&gt;&lt;/param&gt;\n        protected override void AddAttributesToRender(HtmlTextWriter writer)\n        {\n            base.AddAttributesToRender(writer);  //由于AddAttributeToRender()方法实现了对控件基本属性和样式的支持，所以就算需要重写这个方法，也应当调用base.AddAttributeToRender(),以使自定义控件获得基本的功能。\n            writer.AddStyleAttribute(HtmlTextWriterStyle.Width, &quot;120px&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.Height, &quot;35px&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.BackgroundColor, &quot;#0000aa&quot;);\n            writer.AddStyleAttribute(HtmlTextWriterStyle.Cursor, &quot;pointer&quot;);\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>            //如果是链接,回传事件放在href中,使用GetPostBackClientHyperlink\n            string upRef = Page.ClientScript.GetPostBackEventReference(this, null);   //创建onclick事件\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>            writer.AddAttribute(HtmlTextWriterAttribute.Onclick, upRef);              //给onclick事件赋值\n        }\n\n\n        //Click事件属性\n        static object ClickHandler=new object();\n        [Category(&quot;Action&quot;)]\n        public event EventHandler Click\n        {\n            add\n            {\n                Events.AddHandler(ClickHandler,value);\n            }\n            remove\n            {\n                Events.RemoveHandler(ClickHandler,value);\n            }\n        \n        }\n        /// &lt;summary&gt;\n        /// 处理网页回传事件\n        /// 触发控件相应的事件\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;eventArgument&quot;&gt;&lt;/param&gt;\n        public void RaisePostBackEvent(string eventArgument)\n        {\n            EventArgs args=new EventArgs();\n            if (Events[ClickHandler] != null)\n            {\n                (Events[ClickHandler] as EventHandler)(null, args);\n            }\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>html代码</p><div class="language-html ext-html line-numbers-mode"><pre class="language-html"><code> &lt;asp:Label ID=&quot;Label1&quot; runat=&quot;server&quot; Text=&quot;Label&quot;&gt;&lt;/asp:Label&gt;\n    &lt;cc1:IPostBackTest2 ID=&quot;IPostBackTest1&quot; runat=&quot;server&quot; \n        onclick=&quot;IPostBackTest1_Click&quot; /&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>后台代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>  protected void IPostBackTest1_Click(object sender, EventArgs e)\n    {\n        Label1.Text = &quot;111&quot;;\n    }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210855491.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p>',18),l={},t=(0,n(63243).Z)(l,[["render",function(e,i){return s}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,s]of i)n[e]=s;return n}}}]);